import{_ as e,o as i,c as t}from"./chunks/framework.DsiwUQoa.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"OninesixY的小站","text":"何意味？","tagline":"学校你赶紧塌了吧，压死它们那群畜生","actions":[{"theme":"brand","text":"看看吧","link":"Docs"},{"theme":"alt","text":"去GitHub","link":"https://github.com/TheOninesixY/TheOninesixY.github.io"}]},"features":[{"title":"公告","details":"最近我重新初始化了一下我的网站，然后我发现我可以缩短文档路径，去掉了 /Docs/ 开头，现在路径会短一些，但是之前的路径将无法访问，所以会404，然后跳转到主站，也就是 TheOninesixY.github.io，因为我其他的站点都是用Cloudflare Worker 重定向的，GitHub Actions 配置第三方域名太麻烦了，再加上我的域名都在Cloudflare上，所以在Cloudflare上配置会简单许多，但这样有可能在某些情况下跳转到TheOninesixY.github.io，而这个GitHub域名在中国是访问不了的，所以dddd"},{"title":"说明","details":"本网站是我闲着没事干建的，因此质量也许比较差，不过，都闲着没事了，那还要啥质量 <br> 此外，我的文章都很达芬，然后再交给AI让它神秘的优化，然后这坨达芬就更达芬了，然后我没招了，我就直接上架到网站了，然后网站变达芬了"},{"title":"站点","details":"由于我域名多，所以我的网站有很多个域名，这是全部站点，如果其中一个被防火墙封了就换一个访问： <br> - OninesixY.qzz.io <br> - OnsY.qzz.io <br> - OninesixY.dpdns.org <br> - OninesixY.pages.dev <br> - TheOninesixY.github.io"},{"title":"一些问题","details":"1. 为什么我的主域名前面是The开头的 <br> 答：我之前那个ID为OninesixY的GitHub由于邮箱丢失登不上了 <hr> 2. 为什么我网站那么多域名 <br> 答： 因为我觉得多几个总比少几个好 <hr> 3. 为什么我网站那么达芬 <br> 答： 我都闲着没事干了你还要啥质量 <hr> 4. 我为什么要弄这个网站 <br> 答：因为我在很小的时候就希望我有一个网站，那时我还只会用Canva来弄个带许多超链接的项目，然后分享为网址。而现在长大了，我认识到了NodeJS、React、VitePress、Markdown……我就打算用VitePress搭配GitHubActions来搭建一个我小时候觉得搭建起来超难的网站。其实搭建起来我觉得还是蛮简单了，装个NodeJS再装个Yarn，然后初始化一个VitePress项目，改改文件再写写config，再加上一些自己想要的东西，再配置git来上传到仓库，然后配置deploy.yaml，来实现一个超酷的如果识别到git更新中dist文件夹没有更新，就云端build，而如果dist文件夹有更新，就直接用dist文件夹里的，省去云端build，更快 "}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function s(r,o,a,d,l,b){return i(),t("div")}const u=e(n,[["render",s]]);export{h as __pageData,u as default};
